## 4. GraphQL 모듈에서 Notification 관련 파일

### GraphQL Schema
**경로**: `graphql/src/main/resources/graphql/notification.graphqls`

```graphql
type Notification {
  id: ID!
  title: String!
  message: String!
  type: NotificationType!
  isRead: Boolean!
  actionUrl: String
  createdAt: String!
}

enum NotificationType {
  CALL_REQUEST
  MESSAGE
  PROMOTION
  FRIEND_REQUEST
  SYSTEM
}

input SendNotificationInput {
  title: String!
  message: String!
  type: NotificationType!
  actionUrl: String
}

extend type Query {
  notifications(limit: Int, offset: Int): [Notification!]!
  unreadCount: Int!
  notification(id: ID!): Notification
}

extend type Mutation {
  sendNotification(input: SendNotificationInput!): Notification!
  markAsRead(id: ID!): Boolean!
  deleteNotification(id: ID!): Boolean!
}
```

### GraphQL Controller
**경로**: `graphql/src/main/kotlin/com/maum/backend/controller/notification/`

**클래스명**: `NotificationController`

```kotlin
@Controller
class NotificationController(
    private val notificationService: NotificationService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun notifications(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<NotificationResponse> {
        val response = notificationService.getNotifications(userId, limit ?: 20, offset ?: 0)
        return response.notificationsList.map { it.toResponse() }
    }

    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun unreadCount(
        @UserId userId: String,
    ): Int {
        val response = notificationService.getUnreadCount(userId)
        return response.count
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun markAsRead(
        @UserId userId: String,
        @Argument id: String,
    ): Boolean {
        val response = notificationService.markAsRead(userId, id)
        return response.success
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun deleteNotification(
        @UserId userId: String,
        @Argument id: String,
    ): Boolean {
        val response = notificationService.deleteNotification(userId, id)
        return response.success
    }
}
```

### GraphQL Service (gRPC Client)
**경로**: `graphql/src/main/kotlin/com/maum/backend/service/notification/`

**클래스명**: `NotificationService`

```kotlin
@Service
class NotificationService {
    @GrpcClient("notification-grpc")
    private lateinit var stub: NotificationServiceGrpc.NotificationServiceBlockingStub

    @Transactional(readOnly = true)
    fun getNotifications(userId: String, limit: Int, offset: Int): GetNotificationsResponse {
        val request = GetNotificationsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            stub.getNotifications(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.status.code.name, e.status.description)
        }
    }

    @Transactional(readOnly = true)
    fun getUnreadCount(userId: String): GetUnreadCountResponse {
        val request = GetUnreadCountRequest.newBuilder()
            .setUserId(userId)
            .build()
        return try {
            stub.getUnreadCount(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.status.code.name, e.status.description)
        }
    }
}
```

